codeExamples.code:
// 不用陣列：要開很多變數
let score1 = 80;
let score2 = 90;
let score3 = 75;

// 用陣列：一個變數搞定
let scores = [80, 90, 75];

let a = [1, 2, 3];
let b = a;
b.push(4);
console.log(a);

let arr = [10, 20, 30];

// --- 寫入操作（會改變原陣列）---
arr.push(40);
console.log(arr); // [10, 20, 30, 40]（多了 40）

arr[0] = 99;
console.log(arr); // [99, 20, 30, 40]（第一筆被改了）

// splice(起始索引, 刪除幾個, 要新增的元素...)
let arr = ['a', 'b', 'c', 'd'];
arr.splice(1, 1);         // 從索引 1 刪除 1 個
console.log(arr);          // ['a', 'c', 'd']

arr.splice(1, 0, 'x');    // 從索引 1 刪除 0 個，插入 'x'
console.log(arr);          // ['a', 'x', 'c', 'd']

// slice(起始索引, 結束索引)  ※ 不包含結束索引
let arr = [10, 20, 30, 40, 50];
let part = arr.slice(1, 3);
console.log(part);  // [20, 30]（取索引 1、2）
console.log(arr);   // [10, 20, 30, 40, 50]（原陣列沒變）

// indexOf(要找的值)
let fruits = ['apple', 'banana', 'cherry'];
console.log(fruits.indexOf('banana')); // 1（在索引 1）
console.log(fruits.indexOf('grape'));   // -1（找不到）

